"""
MKT Christ Commentary — Psalms chapters 111–117 (Hallel opening + first Hallel cluster)
Run: python3 scripts/zc-christ-psalms-111-117.py
Key decisions:
- Ps 111: v9 'sent redemption / established covenant forever' → Heb 9:12 eternal
  redemption / Heb 13:20 eternal covenant DIRECT; v4 grace-and-compassion →
  Exod 34:6 formula fulfilled in John 1:14; v10 wisdom-begins-with-fear →
  1 Cor 1:24 Christ the wisdom of God
- Ps 112: v9 'gives freely to poor / righteousness endures forever' →
  2 Cor 9:9 DIRECT CITATION Paul quotes verbatim; righteous man of Ps 112
  is also a portrait of Christ himself (the perfectly godly Man)
- Ps 113: vv7-8 raises-poor-from-dust → Luke 1:52-53 Mary's Magnificat
  DIRECT thematic; v9 childless-woman → Elizabeth/Mary; entire Hallel sung
  at Passover = Christ sang this at the Last Supper (Matt 26:30)
- Ps 114: v8 rock-into-water → 1 Cor 10:4 (rock was Christ); v7 earth-trembles
  → Heb 12:26 eschatological shaking through Christ; Exodus as new-Exodus
  paradigm (Luke 9:31 exodon)
- Ps 115: v9-11 threefold trust-in-YHWH = trust in Christ (John 14:1);
  idol-polemic → Col 1:15 Christ the image of invisible God; v17 dead-cannot-
  praise → answered by resurrection (Rev 5:9-10)
- Ps 116: v10 'I believed therefore I spoke' → 2 Cor 4:13 DIRECT CITATION;
  v13 cup-of-salvation → Luke 22:20 Last Supper cup / Passover Hallel; v15
  precious-death-of-saints → Heb 2:9-10 Christ's death most precious; v3
  death-ropes → Acts 2:24 impossible to hold by death
- Ps 117: v1 'Praise LORD, all nations' → Rom 15:11 DIRECT CITATION Paul
  quotes in Gentile-inclusion catena; shortest psalm but universal doxology
  the whole NT is building toward
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer: str, book: str) -> dict:
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    if p.exists():
        return json.loads(p.read_text())
    return {}


def save_comm(layer: str, book: str, data: dict) -> None:
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing: dict, new_data: dict) -> None:
    # INTENT: Write only absent keys so re-running never overwrites manual edits.
    # CHANGE? If key schema changes (e.g. chapter keys become ints), update both
    #   merge_comm and the PSALMS dict below to match.
    # VERIFY: After run: python3 -c "import json; d=json.load(open('data/commentary/
    #   mkt-christ/psalms.json')); print(len(d),'chapters')"
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, text in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = text


PSALMS = {
    "111": {
        "1": "<p>\"Praise the LORD! I will thank the LORD with my whole heart, in the gathering of the upright, in the full congregation\" — the wholehearted praise that opens this acrostic psalm. Hebrews 2:12 quotes Psalm 22:22 in Christ's voice: \"I will declare your name to my brothers and sisters; in the assembly I will sing your praises.\" The gathered congregation praising YHWH is the church gathered around the risen Christ, the one who leads the praise in the midst of his brothers. The wholehearted thanksgiving of Psalm 111:1 is Christ's own song in the assembly.</p>",
        "2": "<p>\"The works of the LORD are great, studied carefully by all who find pleasure in them\" — the contemplation of divine works as the task of the godly community. Christ is both the great work of God and the one who reveals it: \"The Son can do nothing by himself; he can only do what he sees his Father doing, because whatever the Father does the Son also does\" (John 5:19). The works studied with delight are ultimately the works of redemption accomplished in Christ — the disciples who beheld his signs \"believed in him\" (John 2:11).</p>",
        "3": "<p>\"All he does is glorious and majestic, and his righteousness endures forever\" — the permanence of divine righteousness expressed in his works. The righteousness that endures forever is the righteousness revealed in the gospel: \"For in the gospel the righteousness of God is revealed — a righteousness that is by faith from first to last\" (Rom 1:17). The enduring righteousness of YHWH's works reaches its definitive expression in the righteous act of Christ's atoning death (Rom 5:18: \"just as one trespass resulted in condemnation for all people, so also one righteous act resulted in justification and life for all people\").</p>",
        "4": "<p>\"He has made his wonders unforgettable; the LORD is <strong>gracious and full of compassion</strong>\" — the <em>hannun werahhum</em> formula from Exodus 34:6, the great self-revelation of YHWH to Moses at Sinai. John 1:14 makes the connection explicit: \"The Word became flesh and made his dwelling among us. We have seen his glory, the glory of the one and only Son, who came from the Father, full of <strong>grace and truth</strong>.\" The grace-and-compassion of YHWH's wonders is the grace-and-truth that the disciples beheld in the person of Christ — the Sinai formula fulfilled in the Incarnation.</p>",
        "5": "<p>\"He provides food for all who fear him; he is always mindful of his covenant\" — the feeding-God who keeps covenant. Jesus feeds five thousand (John 6:1-13) and then explains: \"I am the <strong>bread of life</strong>. Whoever comes to me will never go hungry, and whoever believes in me will never be thirsty\" (John 6:35). The feeding and covenant-mindfulness of Psalm 111:5 are fulfilled together in Christ who is simultaneously the new covenant's mediator and the bread that sustains covenant life.</p>",
        "6": "<p>\"He showed his people what his works can do, giving them the nations' land as their possession\" — the power of divine works in land-grant. Hebrews 4:8-9: \"For if Joshua had given them rest, God would not have spoken later about another day. There remains, then, a Sabbath-rest for the people of God.\" The land-possession that Joshua achieved was provisional; the true land-grant is the eschatological inheritance secured by Christ — \"the meek will inherit the earth\" (Matt 5:5), the whole renewed creation.</p>",
        "7": "<p>\"Everything he does is faithful and just; all his instructions are reliable\" — the reliable character of divine action and teaching. Jesus says \"I am the way, the truth, and the life\" (John 14:6) — the reliability of divine instructions reaches its embodied form in Christ who is himself truth. Revelation 3:14 calls Christ \"the Amen, the faithful and true witness\" — the faithful-and-just character of Psalm 111:7 is the personal identity of Christ the Witness.</p>",
        "8": "<p>\"They hold firm forever and ever, carried out with complete faithfulness and integrity\" — the permanence of divine instructions. Hebrews 13:8: \"Jesus Christ is the same yesterday and today and forever.\" Matthew 5:18: \"until heaven and earth disappear, not the smallest letter, not the least stroke of a pen, will by any means disappear from the Law until everything is accomplished.\" The holding-firm-forever of divine ordinances is the permanence of Christ who fulfills every one of them and holds them together in his own eternal being.</p>",
        "9": "<p>\"He sent <strong>redemption</strong> (<em>pedut</em>) to his people and established his <strong>covenant forever</strong>. His name is holy and full of awe\" — two of the most direct Messianic categories united in one verse. Hebrews 9:12: \"he entered once for all into the Most Holy Place, not by means of the blood of goats and calves, but by means of his own blood, thus securing an <strong>eternal redemption</strong>.\" Hebrews 13:20: \"the God of peace, who brought back from the dead our Lord Jesus, that great Shepherd of the sheep, through the blood of the <strong>eternal covenant</strong>.\" The redemption sent and the covenant established forever in Psalm 111:9 are the precise terms Hebrews uses to describe what Christ accomplishes — eternal redemption through eternal covenant blood.</p>",
        "10": "<p>\"The fear of the LORD is where <strong>wisdom</strong> begins; those who live by it gain deep understanding. His praise endures forever\" — the concluding wisdom-saying. First Corinthians 1:24: \"Christ the <strong>power of God and the wisdom of God</strong>.\" Colossians 2:3: \"in whom are hidden all the treasures of wisdom and knowledge.\" The fear of the LORD that begins wisdom is, in Christ, the reverence before the one who <em>is</em> Wisdom incarnate. The praise that endures forever is the eternal worship of the Lamb (Rev 5:13).</p>"
    },
    "112": {
        "1": "<p>\"Praise the LORD! How blessed is the one who fears the LORD and finds great joy in his commands!\" — the beatitude that opens this paired acrostic (Ps 111 praises YHWH's character; Ps 112 describes the one who reflects it). The one who finds great joy in YHWH's commands is ultimately Christ himself, who said \"my food is to do the will of him who sent me\" (John 4:34) and \"I have come to do your will, my God\" (Heb 10:7, quoting Ps 40:8). The beatitude of Psalm 112:1 is most fully realized in Jesus, the perfectly godly Man, and derivatively in all who are in him.</p>",
        "2": "<p>\"His children will be a powerful presence in the land; the descendants of the upright will be blessed\" — the generative blessing of the righteous man's lineage. Christ's \"descendants\" are his people, born not of blood but of the Spirit (John 1:13; 3:6). Isaiah 53:10: \"he will see his offspring (<em>zeraʿ</em>) and prolong his days.\" The children of the righteous man in Psalm 112:2 are the spiritual children of Christ — the community born from his death (John 12:24: \"unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit\").</p>",
        "3": "<p>\"Prosperity and riches fill his home, and his righteousness endures forever\" — the lasting righteousness that fills the house. Second Corinthians 8:9: \"you know the grace of our Lord Jesus Christ, that though he was rich, yet for your sake he became poor, so that you through his poverty might become rich.\" The prosperity of Psalm 112:3 is ultimately Christ's eschatological inheritance shared with his people — the riches of the glory of the inheritance that the Spirit is the guarantee of (Eph 1:14, 18).</p>",
        "4": "<p>\"Even in the dark, <strong>light breaks</strong> for the upright; he is gracious, compassionate, and righteous\" — the Exodus 34:6 formula applied now to the godly person who reflects YHWH's character. Jesus says \"I am the <strong>light of the world</strong>\" (John 8:12; 9:5). The light that breaks in darkness for the upright is Christ himself — he is both the source of light and, in his incarnate person, the demonstration of gracious-compassionate-righteous character. The godly man of Psalm 112:4 is a type of Christ, the one who most fully embodies all three divine attributes.</p>",
        "5": "<p>\"It goes well with the one who is generous in lending and manages his business with justice\" — the just and generous person. More directly, Christ is the one who gives himself — \"No one takes my life from me, but I lay it down of my own accord\" (John 10:18). The generosity described in Psalm 112:5 finds its ultimate type in the self-giving of Christ who gives not money but himself for the poor in spirit.</p>",
        "6": "<p>\"The righteous will never be shaken; they will be remembered forever\" — the permanence of the righteous man's standing. Hebrews 12:28: \"since we are receiving a kingdom that cannot be shaken, let us be thankful.\" The unshakeability of the righteous in Psalm 112:6 is derived from Christ's own unshakeability: the one who is \"the same yesterday and today and forever\" (Heb 13:8) is the anchor of the community's eternal standing. \"I give them eternal life, and they shall never perish; no one will snatch them out of my hand\" (John 10:28).</p>",
        "7": "<p>\"He does not fear bad news; his heart is steady, trusting in the LORD\" — the stillness of the trusting heart. Jesus in Gethsemane is the supreme example: even facing the cross, \"not my will but yours\" (Luke 22:42). The steadiness-in-trust of Psalm 112:7 is what Christ embodies in the garden; and through his steadiness, he becomes the ground of the community's steadiness. \"Do not let your hearts be troubled. You believe in God; believe also in me\" (John 14:1).</p>",
        "8": "<p>\"His heart is steady; he will not fear. In the end he will see his enemies get what they deserve\" — the unfearing heart that will witness final vindication. Hebrews 12:2: \"For the joy set before him he endured the cross, scorning its shame, and sat down at the right hand of the throne of God.\" Christ's steadiness through crucifixion leads to the vindication of resurrection and the subjection of every enemy under his feet (Ps 110:1; 1 Cor 15:25). The \"in the end\" of Psalm 112:8 is the eschatological triumph that Christ's resurrection guarantees.</p>",
        "9": "<p>\"He gives <strong>freely to the poor</strong>; his righteousness endures forever; his honor is lifted high\" — Paul quotes this directly in 2 Corinthians 9:9: \"As it is written: 'He has scattered abroad his gifts to the poor; his righteousness endures forever'\" (<strong>DIRECT CITATION</strong>). Paul applies Psalm 112:9 to the generous giving that reflects the gospel character. But the source of all this giving is Christ: \"though he was rich, yet for your sake he became poor\" (2 Cor 8:9). The one who gives freely to the poor is ultimately Christ himself, and those who give generously participate in his character — the honor lifted high is the honor given to Christ at the right hand of the Father (Acts 2:33).</p>",
        "10": "<p>\"The wicked see all this and seethe; they grind their teeth and waste away. What the wicked crave will come to nothing\" — the gnashing-teeth response of the wicked to the righteous man's vindication. Acts 7:54: when Stephen describes the risen Christ at God's right hand, \"they were furious and gnashed their teeth at him.\" The wicked seeing and seething at the godly man's vindication is the scene at Stephen's martyrdom — and at every moment when the truth of Christ's resurrection becomes undeniable to those who reject it. What they crave — the erasure of the righteous and his vindication — comes to nothing.</p>"
    },
    "113": {
        "1": "<p>\"Praise the LORD! Let those who serve the LORD give praise — praise the name of the LORD!\" — Psalm 113 opens the Egyptian Hallel (Pss 113–118), sung at Passover. Jesus and his disciples sang this at the Last Supper (Matt 26:30: \"when they had sung a hymn, they went out to the Mount of Olives\"). The very psalms of the Hallel were on the lips of Christ as he moved toward Gethsemane and the cross. The praise of YHWH's servants in Psalm 113:1 was Christ's own praise on the night he was betrayed.</p>",
        "2": "<p>\"Let the name of the LORD be praised from now and for all time to come!\" — the eternal scope of praise. Philippians 2:9-11: \"God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow... and every tongue acknowledge that Jesus Christ is Lord.\" The praise of YHWH's name \"from now and for all time\" is fulfilled in the eternal worship of Christ (Rev 5:13: \"To him who sits on the throne and to the Lamb be praise and honor and glory and power, for ever and ever!\").</p>",
        "3": "<p>\"From the rising of the sun to where it sets, the name of the LORD deserves all praise!\" — the geographical universality of praise, east to west. Malachi 1:11: \"from the rising to the setting of the sun, my name will be great among the nations.\" Matthew 28:19: \"Go and make disciples of all nations\" — the universal spread of worship from east to west is the Great Commission in geographical terms. The name of Christ is now praised from the rising to the setting of the sun, fulfilling both Psalm 113:3 and Malachi 1:11.</p>",
        "4": "<p>\"The LORD reigns above all nations; his glory soars above the very heavens\" — the transcendent sovereignty of YHWH. Ephesians 1:20-21: Christ was raised and \"seated at his right hand in the heavenly realms, far above all rule and authority, power and dominion, and every name that is invoked.\" The Lord who reigns above all nations in Psalm 113:4 is recognized in the exalted Christ — the one who has been placed above every power and who now exercises the universal sovereignty that the psalm celebrates.</p>",
        "5": "<p>\"Who can compare with the LORD our God, who has his throne so high above\" — the incomparability of YHWH, the <em>mi khamokha</em> tradition (Exod 15:11). In Christ, the incomparability of YHWH becomes personal: \"The Son is the radiance of God's glory and the exact representation of his being\" (Heb 1:3). The one who asks \"who can compare?\" finds the answer in Christ — the only one who is truly the image of the incomparable God (Col 1:15).</p>",
        "6": "<p>\"yet bends down to look at both heaven and earth?\" — the paradox: the highest God condescends to look at what is below. The Incarnation is this condescension taken to its extreme: not merely bending to look but descending to dwell. Philippians 2:6-8: \"Who, being in very nature God, did not consider equality with God something to be used to his own advantage; rather, he made himself nothing, taking the very nature of a servant, being made in human likeness.\" The God who bends down to look in Psalm 113:6 is the God who bends down to become flesh in the Incarnation.</p>",
        "7": "<p>\"He lifts the poor out of the dust and raises the needy from the garbage heap\" — the divine reversal, lifting the lowest. Luke 1:52-53 (Mary's Magnificat): \"He has brought down rulers from their thrones but has <strong>lifted up the humble</strong>. He has filled the hungry with good things but has sent the rich away empty.\" Mary's song of the Incarnation is a direct riff on Psalm 113:7-8 — the divine reversal that the psalm celebrates is the very reversal that the Incarnation sets in motion. The poor lifted from the dust is every soul whom Christ receives (Matt 11:28-30; Luke 7:22).</p>",
        "8": "<p>\"to seat them alongside princes — the princes of his own people\" — the elevation to royal dignity. Revelation 1:6: Christ \"has made us to be a kingdom and priests to serve his God and Father.\" The dusty-poor seated alongside princes in Psalm 113:8 are the community of the resurrection — the ones who will reign with Christ (Rev 20:4; 2 Tim 2:12: \"if we endure, we will also reign with him\"). The seating alongside princes is the eschatological dignity Christ bestows on those he raises from the ash heap.</p>",
        "9": "<p>\"He gives the childless woman a home, turning her into a glad mother of children. Praise the LORD!\" — the barren woman who becomes a fruitful mother: Sarah (Gen 18:11-14), Rebekah (Gen 25:21), Rachel (Gen 30:22), Hannah (1 Sam 1-2), Elizabeth (Luke 1:7, 36). The last and greatest instance is Mary, the virgin who conceives by the Spirit (Luke 1:35). Christ is born of one for whom \"the Mighty One has done great things\" (Luke 1:49) — the child of a divine reversal of all natural expectation. The glad mother of children at the end of this Hallel-opening psalm is the type of Mary, and Mary is the type of the church which \"is the mother of us all\" (Gal 4:26).</p>"
    },
    "114": {
        "1": "<p>\"When Israel came out of Egypt, when the family of Jacob left a people of foreign speech\" — the Exodus as the paradigmatic act of divine redemption. First Corinthians 10:1-11 explicitly interprets the Exodus typologically: the events in the wilderness \"were written down as warnings for us, on whom the culmination of the ages has come.\" Christ enacts the definitive new Exodus — Luke 9:31 says Moses and Elijah spoke at the Transfiguration about \"his departure (<em>exodon</em>), which he was about to bring to fulfillment at Jerusalem.\" The Exodus of Psalm 114:1 is the prototype; Christ's death and resurrection is the antitype.</p>",
        "2": "<p>\"Judah became God's holy place, Israel his kingdom\" — the Exodus establishing YHWH's sanctuary and kingdom. First Peter 2:9: \"But you are a chosen people, a royal priesthood, a holy nation, God's special possession.\" The community born from the Exodus becomes God's sanctuary and kingdom — and the community born from the new Exodus (Christ's death and resurrection) is the new Israel, God's holy dwelling in the Spirit (Eph 2:21-22: \"In him the whole building is joined together and rises to become a holy temple in the Lord\").</p>",
        "3": "<p>\"The sea saw and fled; the Jordan reversed its course\" — the cosmic response to YHWH's presence: the Red Sea parts, the Jordan stops. Jesus' baptism in the Jordan (Matt 3:13-17) re-enacts Israel's crossing — he goes through the waters as the true Israel, emerges to receive the Spirit's descent and the Father's voice: \"This is my beloved Son.\" The Jordan reversal of Psalm 114:3 is re-enacted in the baptism of Christ who goes through the waters as Israel's head and comes out as the acknowledged Son.</p>",
        "4": "<p>\"The mountains leaped like rams and the hills like young lambs\" — the Sinai theophany causes creation to convulse. This cosmic responsiveness to the divine presence accompanies Christ's key moments: his birth (the star of Matt 2:2), his death (\"the earth shook and the rocks split,\" Matt 27:51), his resurrection (\"There was a violent earthquake,\" Matt 28:2), and his return (\"the heavenly bodies will be shaken,\" Matt 24:29). The mountains leaping at the Sinai theophany are the type of creation's response to the presence of the incarnate Son.</p>",
        "5": "<p>\"What happened to you, sea, that you ran? And you, Jordan — that you reversed your course?\" — the psalmist interrogates the creation, demanding an account of its dramatic response. The implicit answer is: YHWH was there. At Christ's baptism, the heavens \"were opened\" (Matt 3:16) — creation responds to the arrival of the one whose presence is greater than the theophany at Sinai. The interrogation of the sea and Jordan makes the point that only the divine presence explains such events; and Christ's presence provokes equal signs throughout the Gospels.</p>",
        "6": "<p>\"You mountains — why did you leap like rams? You hills, like young lambs?\" — the rhetorical question repeated. Hebrews 12:18-24 contrasts the terrifying Sinai theophany with the new covenant's \"Mount Zion, the city of the living God... Jesus the mediator of a new covenant, and to the sprinkled blood that speaks a better word than the blood of Abel.\" The mountains that leaped at Sinai are surpassed by the eschatological Mount Zion to which the new covenant community comes through Christ — the greater theophany in a better Mediator.</p>",
        "7": "<p>\"Tremble before the Lord, O earth — tremble before the God of Jacob\" — the call for creation to tremble before YHWH. Hebrews 12:26-27: \"At that time his voice shook the earth, but now he has promised, 'Once more I will shake not only the earth but also the heavens.' The words 'once more' indicate the removing of what can be shaken — that is, created things — so that what cannot be shaken may remain.\" The earth-trembling at the Exodus theophany is the prototype of the eschatological cosmic shaking that comes through Christ — the final trembling before the Lord who comes in judgment.</p>",
        "8": "<p>\"who turns solid rock into a pool of water and hard flint into a flowing spring\" — the Meribah miracle: water from the rock (Exod 17:6; Num 20:11). First Corinthians 10:4: \"they drank from the spiritual Rock that followed them, and <strong>the Rock was Christ</strong>.\" The water from the rock in Psalm 114:8 receives among the most direct Christological identifications in the entire NT — Paul says the preexistent Christ was the rock. John 7:37-38: \"Let anyone who is thirsty come to me and drink. Whoever believes in me, as Scripture has said, rivers of living water will flow from within them.\" The hard flint turned to flowing spring is Christ himself, poured out through the Spirit.</p>"
    },
    "115": {
        "1": "<p>\"Not to us, O LORD — not to us — but to <strong>your name give glory</strong>, because of your steadfast love and your faithfulness\" — the foundational doxological posture: glory belongs to YHWH, not to human agents. Jesus lived this perfectly: \"I do not accept glory from human beings\" (John 5:41); \"I am not seeking glory for myself; but there is one who seeks it, and he is the judge\" (John 8:50). John 17:4: \"I have brought you glory on earth by finishing the work you gave me to do.\" The prayer of Psalm 115:1 — that glory go to the divine name — is the prayer Christ embodies in his entire life and death.</p>",
        "2": "<p>\"Why should the nations say, 'Where is their God?'\" — the taunt of the nations when Israel suffers. This same taunt surrounded Christ's crucifixion: \"He trusts in God. Let God rescue him now if he wants him, for he said, 'I am the Son of God'\" (Matt 27:43). The scoffers at Calvary ask exactly the question of Psalm 115:2 — where is God for this one? The answer is the resurrection: God vindicates his own by raising Christ, answering every taunt with the power of new life (Acts 2:24).</p>",
        "3": "<p>\"But our God is enthroned in the heavens; he does whatever he pleases\" — the sovereign freedom of YHWH. Jesus in Gethsemane: \"not what I will, but what you will\" (Mark 14:36) — the sovereign pleasure of the Father is the will Christ submits to, even when that pleasure includes the cross. Acts 4:28: \"They did what your power and will had decided beforehand should happen\" — the events of the passion were within the sovereign pleasure of YHWH. The God who does whatever he pleases does his most sovereign act in the cross and resurrection.</p>",
        "4": "<p>\"Their idols are silver and gold — nothing more than what human hands have made\" — the idol polemic. Colossians 1:15: Christ is \"the <strong>image of the invisible God</strong>.\" The idols are humanly manufactured images; Christ is the divinely given image. Acts 17:29: \"We should not think that the divine being is like gold or silver or stone — an image made by human design and skill.\" The idol critique of Psalm 115:4-8 points toward the need for the true image — the one not made by human hands but given by God in the Incarnation.</p>",
        "5": "<p>\"They have mouths but cannot speak; they have eyes but cannot see\" — the impotent idol. In contrast, Christ <em>speaks</em> with divine authority (Matt 7:29), <em>sees</em> with divine perception (John 2:25: \"he knew what was in each person\"), and hears with divine compassion (John 11:35). The catalogue of idol-failures in Psalm 115:5-7 is a negative image of everything Christ positively is: the living one who speaks, sees, hears, acts — the true image of the living God (Col 1:15).</p>",
        "6": "<p>\"They have ears but cannot hear; they have noses but cannot smell\" — the idol cannot perceive. Jesus \"heard\" every cry — the blind Bartimaeus (Mark 10:47-48), the desperate Syrophoenician woman (Matt 15:22-28), the leper's cry (Mark 1:40). Isaiah 50:4-5: \"The Sovereign LORD has opened my ears\" — the Servant's open ear is the opposite of the idol's deaf silence. Christ is the Servant with an ear always open to the human cry.</p>",
        "7": "<p>\"They have hands but cannot feel anything; they have feet but cannot walk; they produce no sound from their throat\" — the idol is totally unresponsive. Jesus touches the leper (Mark 1:41: \"filled with compassion, Jesus reached out his hand and touched the man\"), walks toward the suffering (Matt 14:25-26), and raises his voice in the temple (John 7:37). The totally unresponsive idol of Psalm 115:7 is the foil for the fully responsive incarnate Lord who heals through touch, moves toward the hurting, and speaks words of life.</p>",
        "8": "<p>\"Those who make them will end up like them — and so will everyone who puts their trust in them\" — the moral conformity principle: worshipers become like what they worship. Second Corinthians 3:18: \"we all, who with unveiled faces contemplate the Lord's glory, are being <strong>transformed into his image</strong> with ever-increasing glory, which comes from the Lord, who is the Spirit.\" The inverse of the idol-maker's deformation is the Christ-worshiper's transformation — those who trust the living God in Christ are progressively conformed to the image of the Son (Rom 8:29).</p>",
        "9": "<p>\"Israel, put your <strong>trust in the LORD</strong>! He is their help and their shield\" — the first of three calls to trust, covering Israel, Aaron, and all who fear. John 14:1: \"Do not let your hearts be troubled. <strong>You believe in God; believe also in me</strong>\" — Jesus explicitly extends the trust-in-YHWH call to himself. The help-and-shield formula for YHWH becomes the description of what Christ is for his people: \"the Lord is my helper; I will not be afraid\" (Heb 13:6, quoting Ps 118:6) and the \"shield of faith\" (Eph 6:16) that comes through trust in him.</p>",
        "10": "<p>\"House of Aaron, put your trust in the LORD! He is their help and their shield\" — the priestly house called to trust. Christ is the great High Priest (Heb 4:14) who fulfills and supersedes the Aaronic priesthood — and he is also the one in whom Aaron's house now trusts for access to God. Hebrews 7:11: \"If perfection could have been attained through the Levitical priesthood... why was there still need for another priest?\" The House of Aaron who trusted YHWH ultimately trusted forward toward the one who would be their perfect high priest.</p>",
        "11": "<p>\"All who fear the LORD, put your trust in the LORD! He is their help and their shield\" — the universal call beyond Israel and the priesthood to all who fear God. Acts 10:34-35: \"God does not show favoritism but accepts from every nation the one who fears him and does what is right.\" The inclusion of all God-fearers in the call of Psalm 115:11 is the opening toward the Gentile mission that Christ commissions (Matt 28:19-20). All who fear YHWH from every nation are now called to put their trust in the Lord Christ — the widest possible invitation.</p>",
        "12": "<p>\"The LORD has remembered us and he will bless us; he will bless the house of Israel; he will bless the house of Aaron\" — the divine memory as the basis of blessing. Luke 1:54-55: Mary sings that God \"has helped his servant Israel, remembering to be merciful to Abraham and his descendants forever.\" God's remembering in the Incarnation is the fulfillment of the remembering that Psalm 115:12 announces. The blessing of Israel and Aaron's house flows from the divine memory of the covenant — and the blessing of all nations flows from the covenant fulfilled in Christ.</p>",
        "13": "<p>\"He will bless all who fear the LORD, the small as well as the great\" — no status distinction in the blessing. Luke 1:52: \"He has brought down rulers from their thrones but has lifted up the humble.\" Matthew 18:4: \"whoever takes the lowly position of this child is the greatest in the kingdom of heaven.\" Christ's inversion of social hierarchy — the small blessed as well as the great — is embedded in the Hallel he sings at Passover on the night of his arrest.</p>",
        "14": "<p>\"May the LORD grant you increase — you and your children!\" — the blessing of generational increase. John 12:24: \"unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit.\" The increase of Psalm 115:14 is ultimately the fruitfulness of the resurrection — Christ's death produces many children (Heb 2:13 quotes Isa 8:18: \"Here am I, and the children God has given me\"). The divine grant of increase is the multiplication of the church through the gospel of the risen Christ.</p>",
        "15": "<p>\"May you be blessed by the LORD — he who made both heaven and earth!\" — the Creator's blessing. Genesis 14:19: \"Blessed be Abram by God Most High, Creator of heaven and earth\" — the Melchizedek blessing that Christ fulfills as the eternal priest (Heb 7:1-3). The blessing from the Creator-God echoes through the Melchizedek tradition and arrives in Christ the priest-king who mediates the Creator's blessing to all Abraham's children (Gal 3:29: \"if you belong to Christ, then you are Abraham's seed, and heirs according to the promise\").</p>",
        "16": "<p>\"The highest heavens belong to the LORD, but the earth he has given to the children of mankind\" — the eschatological land-grant. Matthew 5:5: \"Blessed are the meek, for they will <strong>inherit the earth</strong>.\" The earth \"given to the children of mankind\" in Psalm 115:16 points toward the eschatological inheritance of the new earth, which the Beatitudes promise to the meek — those who are heirs because they are in Christ the true Heir of all things (Heb 1:2).</p>",
        "17": "<p>\"The <strong>dead cannot praise the LORD</strong>, nor can any who descend into the silence of the grave\" — the pre-resurrection horizon of the psalmist. Christ's resurrection directly shatters this limitation: Acts 2:31: \"he was not abandoned to the realm of the dead, nor did his body see decay.\" Revelation 5:9-13: every creature, including the formerly dead raised in Christ, sings to the Lamb — the dead who could not praise in Psalm 115:17 become the dead who rise to praise, because Christ has broken the silence of the grave.</p>",
        "18": "<p>\"But we will praise the LORD from this moment on, now and forever. Praise the LORD!\" — the vow of perpetual praise. Revelation 22:3-5: \"His servants will serve him... and they will reign for ever and ever.\" The \"from now and forever\" of Psalm 115:18 is the eternal praise of the new creation — a praise that will never end because the one praised lives and reigns forever. The Hallel's closing promise of perpetual praise is the preview of the eternal worship scene in Revelation before the Lamb.</p>"
    },
    "116": {
        "1": "<p>\"I love the LORD because he has heard my voice and my pleas for mercy\" — the opening of the great Passover thanksgiving psalm, which Christ sang at the Last Supper (Matt 26:30). Hebrews 5:7: \"During the days of Jesus's life on earth, he offered up prayers and petitions with fervent cries and tears to the one who could save him from death, and he was heard because of his reverent submission.\" The speaker of Psalm 116 who loves YHWH because he was heard is a type of Christ, whose Gethsemane prayer was answered — not by removal of the cup but by the resurrection that followed the cross.</p>",
        "2": "<p>\"Because he bent his ear down to listen to me, I will call on him for as long as I live\" — the lifelong commitment to prayer founded on answered prayer. John 11:41-42: \"Jesus looked up and said, 'Father, I thank you that you have heard me. I knew that you always hear me.'\" The confidence that YHWH's ear is bent to listen is what Christ embodies — his prayer life is defined by the certainty that the Father hears him. The perpetual calling-on-YHWH of Psalm 116:2 is Christ's own prayer posture (Luke 18:1: \"they should always pray and not give up\").</p>",
        "3": "<p>\"Death's ropes wrapped around me; the grip of Sheol closed in; I was trapped in distress and anguish\" — the near-death experience that the thanksgiving follows. Acts 2:24: God raised Jesus, \"freeing him from the agony of death, because it was <strong>impossible for death to keep its hold on him</strong>.\" The death-ropes and Sheol-grip of Psalm 116:3 are precisely what could not hold Christ — not because he avoided death but because he absorbed it fully and was raised through it. The impossible grip of death on Christ is loosened by the power of resurrection.</p>",
        "4": "<p>\"Then I cried out the name of the LORD: 'Please, LORD — rescue my life!'\" — the urgent prayer in extremis. Matthew 26:39: \"My Father, if it is possible, may this cup be taken from me. Yet not as I will, but as you will.\" Luke 22:44: \"And being in anguish, he prayed more earnestly.\" The desperate name-cry of Psalm 116:4 is Gethsemane — the Son crying out for rescue in extremity, the cry that the Father answers not by removing the cross but by raising the Crucified.</p>",
        "5": "<p>\"The LORD is gracious and righteous; our God is full of compassion\" — the Exodus 34:6 formula confessed in personal deliverance. At Christ's cross, the paradox of this verse reaches its apex: God is simultaneously <em>righteous</em> (the sin-bearing must happen) and <em>gracious/compassionate</em> (he provides the substitute himself). Romans 3:26: God is \"just and the one who justifies those who have faith in Jesus.\" The grace-and-righteousness of YHWH are not in tension at the cross but reconciled — the most gracious act is simultaneously the most righteous.</p>",
        "6": "<p>\"The LORD protects those who are simple-hearted; when I was at my lowest, he came to my rescue\" — the divine care for the childlike and the broken. Matthew 11:25: \"you have hidden these things from the wise and learned, and revealed them to little children.\" Matthew 18:3: \"unless you change and become like little children, you will never enter the kingdom of heaven.\" Christ himself came as \"gentle and humble in heart\" (Matt 11:29), the protector of the simple and the rescuer of the broken.</p>",
        "7": "<p>\"Come to your rest again, my soul, for the LORD has been good to you\" — the soul returning to rest after distress. Matthew 11:28-29: \"Come to me, all you who are weary and burdened, and I will give you rest... you will find rest for your souls.\" The rest-for-the-soul that Psalm 116:7 announces is what Christ offers in his own person — not a return to the pre-crisis state but a rest that is better than anything before: \"my rest\" (Heb 4:10) that flows from entering Christ's completed work.</p>",
        "8": "<p>\"You have rescued my soul from death, my eyes from tears, my feet from stumbling\" — the triple rescue: from death, tears, and falling. Acts 2:27 (quoting Ps 16:10): \"you will not abandon me to the realm of the dead, you will not let your holy one see decay.\" Jude 24: \"To him who is able to keep you from stumbling and to present you before his glorious presence without fault and with great joy.\" The three rescues of Psalm 116:8 are the three gifts of Christ's resurrection: death defeated, tears ending (Rev 21:4), and stumbling prevented by the one who is himself the Way.</p>",
        "9": "<p>\"I will walk in the presence of the LORD in the land of the living\" — the ongoing life in divine presence after rescue from death. John 11:25-26: \"I am the resurrection and the life. The one who believes in me will live, even though they die; and whoever lives by believing in me will never die.\" The walking in the presence of YHWH in the land of the living is the experience of those who are in Christ — the life of resurrection begun now and completed in the new creation (Rev 21:3: \"God's dwelling place is now among the people, and he will dwell with them\").</p>",
        "10": "<p>\"I trusted, even while I cried out: 'I am in great distress'\" — trust maintained through suffering. Paul quotes this directly in 2 Corinthians 4:13: \"It is written: 'I believed; therefore I have spoken.' Since we have that same spirit of faith, we also believe and therefore speak\" (<strong>DIRECT CITATION</strong>). Paul applies Psalm 116:10 to the apostolic ministry of suffering-and-proclamation — believing even while in the clay jars of human weakness (2 Cor 4:7-12). The trust-while-crying of Psalm 116:10 is the spirit of faith that drives the church's proclamation despite persecution.</p>",
        "11": "<p>\"In my panic I declared, 'Every human being is a liar'\" — the moment of extremity revealing human unreliability. Romans 3:4: \"Let God be true, and every human being a liar\" — Paul echoes this verse to argue that God's faithfulness holds even when humans are unfaithful. The liar-declaration of Psalm 116:11 finds its NT home in Paul's demonstration that only God (and the God-man Christ) is ultimately reliable; human testimony and covenant-keeping fail, but \"if we are faithless, he remains faithful\" (2 Tim 2:13).</p>",
        "12": "<p>\"What can I give back to the LORD for all the good he has done for me?\" — the question of grateful response to redemption. Romans 12:1: \"Therefore, I urge you, brothers and sisters, in view of God's mercy, to offer your bodies as a living sacrifice, holy and pleasing to God — this is your true and proper worship.\" The \"what shall I give back\" of Psalm 116:12 is answered in the total self-offering that the gospel calls forth — modeled by Christ who \"offered himself unblemished to God\" (Heb 9:14) and who calls his people to the same path.</p>",
        "13": "<p>\"I will take up the <strong>cup of salvation</strong> and call on the name of the LORD\" — the cup taken up in thanksgiving at the Passover. This is one of the most direct connections to the Last Supper: Luke 22:20: \"In the same way, after the supper he took the <strong>cup</strong>, saying, 'This cup is the new covenant in my blood, which is poured out for you.'\" Jesus sang this psalm at the Passover and then took the cup of the new covenant — the \"cup of salvation\" of Psalm 116:13 becomes the cup of Christ's atoning blood through which salvation is accomplished. The Hallel anticipates the eucharistic cup.</p>",
        "14": "<p>\"I will fulfill my vows to the LORD in the presence of all his people\" — the public thanksgiving vow. Christ's resurrection appearances before the community — culminating in \"more than five hundred of the brothers and sisters at the same time\" (1 Cor 15:6) — are the fulfillment of the public presence before \"all his people.\" The vow fulfilled before all the people is the resurrection-declaration that the Father makes through the empty tomb — the public vindication of the one who lived in faithful covenant obedience.</p>",
        "15": "<p>\"The LORD takes the death of his faithful ones very seriously\" — the divine valuing of the deaths of the <em>hasidim</em> (faithful ones). Hebrews 2:9-10: \"we see Jesus, who was made a little lower than the angels, now crowned with glory and honor because he suffered death, so that by the grace of God he might taste death for everyone. In bringing many sons and daughters to glory, it was fitting that God... should make the pioneer of their salvation perfect through what he suffered.\" Christ's death is the most precious of all deaths — the death of the perfectly faithful one, which is why it accomplishes what no other death could accomplish.</p>",
        "16": "<p>\"LORD, I am your servant — your servant, the son born of your maidservant. You have set me free from my bonds\" — the servant-son identity and liberation. Philippians 2:7: Christ \"took the very nature of a <strong>servant</strong> (<em>doulou</em>), being made in human likeness.\" Isaiah 42:1: \"Here is my servant, whom I uphold, my chosen one in whom I delight.\" Luke 1:38: Mary declares herself \"the servant (<em>doule</em>) of the Lord\" — and her son is the Servant-Son born of the servant-maid. The son of the maidservant set free from bonds is the type fulfilled in Christ who, born of the virgin-servant, liberates all from the bondage of sin and death (Heb 2:15).</p>",
        "17": "<p>\"I will bring you a thanksgiving offering and call out the name of the LORD\" — the thanksgiving sacrifice. Hebrews 13:15: \"Through Jesus, therefore, let us continually offer to God a sacrifice of praise — the fruit of lips that openly profess his name.\" The thanksgiving offering of Psalm 116:17 is fulfilled in the perpetual praise-sacrifice that the church offers through Christ the great high priest. The \"calling on the name of the LORD\" at the Passover Hallel becomes the calling on the name of Christ in the new covenant community (Acts 2:21; Rom 10:13).</p>",
        "18": "<p>\"I will fulfill my vows to the LORD in the presence of all his people\" — the vow-fulfillment repeated for emphasis, underscoring its public and communal character. Romans 1:4-5: Christ \"was appointed the Son of God in power by his resurrection from the dead: Jesus Christ our Lord. Through him we received grace and apostleship to call all the Gentiles to the obedience that comes from faith.\" The public vow-fulfillment before all the people becomes the apostolic proclamation before all nations — the resurrection is the divine fulfillment of every vow.</p>",
        "19": "<p>\"right in the courtyards of the LORD's house, in your very midst, O Jerusalem. Praise the LORD!\" — the vow fulfilled in the temple courts, in Jerusalem. Luke 24:52-53: \"Then they worshiped him and returned to Jerusalem with great joy. And they stayed continually at the temple, praising God.\" After the resurrection and ascension, the disciples return to Jerusalem and to the temple courts — fulfilling in the new-covenant community the exact location the Hallel's culminating praise calls for. The \"Praise the LORD!\" in Jerusalem's courts is the disciples' post-resurrection joy, the conclusion of the Passover psalm Christ himself sang the night before he died.</p>"
    },
    "117": {
        "1": "<p>\"Praise the LORD, all <strong>nations</strong>! Praise him, all peoples of the earth!\" — the shortest psalm in the Psalter, but theologically among the most momentous: a universal summons to all nations and peoples to worship YHWH. Paul quotes this verse directly in Romans 15:11 as part of a four-text catena proving that the Gentiles will glorify God through Christ: \"'Praise the Lord, all you Gentiles; let all the peoples extol him'\" (<strong>DIRECT CITATION</strong>). Romans 15:9-12 assembles Psalm 18:49, Deuteronomy 32:43, Psalm 117:1, and Isaiah 11:10 to demonstrate that the inclusion of the Gentiles is not an afterthought but the goal of Israel's entire covenant history. Psalm 117:1 sits at the climax of this argument: all nations praising YHWH is what the Messiah came to accomplish (Matt 28:19-20; Acts 1:8; Rev 7:9-10).</p>",
        "2": "<p>\"For his <strong>steadfast love</strong> (<em>hesed</em>) toward us is great, and the <strong>faithfulness</strong> (<em>emet</em>) of the LORD endures forever. Praise the LORD!\" — the Exodus 34:6-7 formula compressed to its essence: great love, enduring faithfulness. John 1:14: \"the Word became flesh and made his dwelling among us. We have seen his glory, the glory of the one and only Son, who came from the Father, full of <strong>grace and truth</strong>.\" The <em>hesed</em> and <em>emet</em> of Psalm 117:2 are the <em>charis</em> and <em>aletheia</em> of the Incarnation — the steadfast love and faithfulness of YHWH become embodied in the person of Jesus Christ. Hebrews 13:8: \"Jesus Christ is the same yesterday and today and forever\" — his faithfulness endures not just forever in the abstract but in his own eternal, unchanging person. The two-verse psalm that calls all nations to praise is grounded in the character of the God who comes in Christ: love that will not let go, faithfulness that will not fail.</p>"
    }
}


# INTENT: Write mkt-christ entries for Psalms 111-117 (Hallel cluster), adding 76
#   verses. merge_comm ensures only absent keys are written — safe to re-run.
# CHANGE? If data/commentary/mkt-christ/psalms.json schema changes, update
#   load_comm/save_comm and PSALMS dict structure above.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
#   psalms.json')); print(len(d),'chapters'); print('117 v1:',
#   d.get('117',{}).get('1','MISSING')[:80])"
def main() -> None:
    existing = load_comm("mkt-christ", "psalms")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, PSALMS)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "psalms", existing)
    print(f"{len(existing)} chapters, {after} verse entries total")
    print(f"Added {after - before} new entries this run")

    checks = [
        ("111", "9", "eternal"),
        ("112", "9", "freely"),
        ("113", "7", "lifted"),
        ("114", "8", "Rock"),
        ("115", "17", "dead"),
        ("116", "10", "believed"),
        ("116", "13", "cup"),
        ("117", "1", "nations"),
    ]
    for ch, v, keyword in checks:
        entry = existing.get(ch, {}).get(v, "MISSING")
        status = "OK" if keyword.lower() in entry.lower() else f"MISSING keyword '{keyword}'"
        print(f"  Ps {ch}:{v} — {status}")


if __name__ == "__main__":
    main()
